        }

        .btn-default {
            padding: 20px 30px;
            background: #232323;
            color: #fff;
            text-decoration: none;
            position: relative;
            -webkit-transform: translate3d(0, 0, 0);
            -moz-transform: translate3d(0, 0, 0);
            -ms-transform: translate3d(0, 0, 0);
            -o-transform: translate3d(0, 0, 0);
            transform: translate3d(0, 0, 0);
            background: 0 0
        }

        .btn-default:active,
        .btn-default:focus,
        .btn-default:hover {
            color: #fff !important
        }

        .btn-default:before {
            display: block;
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: #232323;
            content: "";
            z-index: -2
        }

        .btn-default:after {
            display: block;
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: #565656;
            content: "";
            z-index: -1;
            opacity: 0;
            -moz-transform: scaleX(0);
            -o-transform: scaleX(0);
            -webkit-transform: scaleX(0);
            transform: scaleX(0);
            -moz-transform-origin: 0 0;
            -o-transform-origin: 0 0;
            -webkit-transform-origin: 0 0;
            transform-origin: 0 0;
            -moz-transition: transform .4s cubic-bezier(.77, 0, .175, 1), opacity 50ms linear .4s;
            -o-transition: transform .4s cubic-bezier(.77, 0, .175, 1), opacity 50ms linear .4s;
            -webkit-transition: transform .4s cubic-bezier(.77, 0, .175, 1), opacity 50ms linear;
            -webkit-transition-delay: 0s, .4s;
            transition: transform .4s cubic-bezier(.77, 0, .175, 1), opacity 50ms linear .4s
        }

        .btn-default:hover:after {
            width: 100%;
            opacity: 1;
            -moz-transform: scaleX(1);
            -o-transform: scaleX(1);
            -webkit-transform: scaleX(1);
            transform: scaleX(1);
            -moz-transition-delay: 0s;
            -o-transition-delay: 0s;
            -webkit-transition-delay: 0s;
            transition-delay: 0s
        }

