            bottom: 10px;
            color: #fff;
            width: 100%;
            text-align: center;
            font-size: 16px
        }

        .contentPopin div.contenuPopin {
            position: fixed;
            left: 50%;
            top: 50%;
            transform: translate(-50%, -50%);
            width: 90%;
            height: 90%;
            max-width: 1000px;
            max-height: 800px;
            z-index: 10001
        }

        .contentPopin div.contenuPopin {
            height: 100%
        }

        .contentPopin div.titrePopin {
            position: relative;
            display: flex;
            flex-direction: column;
            flex-wrap: nowrap;
            justify-content: center;
            width: 100%;
            background-color: #333;
            padding: 15px 20px 15px 20px;
            font-size: 18px;
            color: #fff;
            font-weight: 700;
            text-transform: uppercase
        }

        .contentPopin div.titrePopin:not(.col-xs-12) {
            position: sticky;
            top: 0;
            z-index: 100;
            height: 70px
        }

        .contentPopin div.titrePopin h2 {
            margin: 0;
            font-size: 17px;
            text-transform: initial;
            text-align: center;
            font-weight: 700
        }

        .contentPopin div.contenuPopin {
            max-height: calc(800px - 63px);
            height: 90%;
            overflow-y: auto;
            background-color: #fff;
            padding: 2%
        }

        .contentPopin div.titrePopin h2 span.closePopin {
            position: absolute;
            right: 3%;
            top: 50%;
            transform: translateY(-50%);
            cursor: pointer;
            font-size: 20px
        }

        .contentPopin div.titrePopin h2 span[class*=ei_gly] {
            color: #bad606;
            margin-right: 15px
        }
    </style>
