    <style>
        :root {
            font-size: 16px;
            color-scheme: light dark;
            --color-primary: hsl(68, 95%, 43%);
            --color-primary-hover: hsl(68, 72%, 72%);
            --font-color-primary: #000000;
            --font-color-secondary: hsl(0, 0%, 20%);
            --font-color-tertiary: hsl(0, 0%, 0%);
            --bg-primary: hsl(0, 0%, 100%);
            --bg-secondary: hsl(0, 0%, 100%);
            --bg-tertiary: hsl(0, 0%, 100%);
            --border-color: hsl(214, 32%, 91%);
            --border-color-2: hsl(220, 4%, 16%);
            --box-shadow: 0px 24px 64px 0px hsla(0, 0%, 0%, 0.08);
            --blur-color: hsla(0, 0%, 0%, 0.38);
            --gradient: linear-gradient(180deg, #fff 60.02%, #f1f1f1 100%);
            --invert: invert(0);
            --btn-secondary-color: hsl(68, 95%, 43%);
            --shadow-progressive: linear-gradient(180deg, rgba(255, 255, 255, 0), var(--bg-secondary) 100%);
            --shadow-color-1: rgba(255, 255, 255, 0);
            --shadow-color-2: var(--bg-secondary)
        }

        @media(prefers-color-scheme: dark) {
            :root {
                --color-primary: hsl(68, 95%, 43%);
                --color-primary-hover: hsl(68, 72%, 72%);
                --font-color-primary: #ffffff;
                --font-color-secondary: hsl(0, 0%, 80%);
                --font-color-tertiary: hsl(0, 0%, 0%);
                --bg-primary: hsl(0, 0%, 14%);
                --bg-secondary: hsl(0, 0%, 0%);
                --bg-tertiary: hsl(0, 0%, 20%);
                --border-color: hsl(214, 32%, 91%);
                --border-color-2: hsl(220, 4%, 16%);
                --box-shadow: 0px 24px 64px 0px hsla(0, 0%, 35%, 0.08);
                --blur-color: hsla(0, 0%, 55%, 0.38);
                --gradient: linear-gradient(180deg, hsl(0, 0%, 0%) 60.02%, hsl(0, 0%, 14%) 100%);
                --invert: invert(1);
                --btn-secondary-color: hsl(0, 0%, 100%);
                --shadow-progressive: linear-gradient(180deg, rgba(255, 255, 255, 0), var(--bg-secondary) 100%);
                --shadow-color-1: rgba(255, 255, 255, 0);
                --shadow-color-2: var(--bg-secondary)
            }
        }

        a {
            cursor: pointer
        }

        .divider {
            width: 76px;
            height: 4px;
            border-radius: 8px
        }

        .divider_green {
            background: #bad606
        }

        .divider_black {
            background: #000
        }

        .divider_white {
            background: #fff
        }

        .line-divider {
            height: 32px;
            width: 100%;
            position: relative
        }

        .line-divider::before {
            content: "";
            position: absolute;
            width: 100%;
            height: 1px;
            top: 50%;
            translate: 0 -50%;
            background: rgba(0, 0, 0, .08)
        }

        .grey-gradient {
            background: var(--gradient)
        }

        .gradient {
            background: var(--gradient)
        }

        .section-padding {
            padding: 30px 4%
        }

        @media all and (max-width: 768px) {
            .section-padding {
                padding: 15px 4% !important
            }
        }

        .section-margin {
            margin: 0 64px
        }

        .mw-container {
            max-width: 1440px;
            margin: auto
        }

        .of-visible {
            overflow: visible
        }

        h2.separate {
            margin-top: 30px;
            position: relative
        }

        h2.separate:after {
            content: "";
            position: absolute;
            width: 76px;
            height: 4px;
            background-color: #bad606;
            left: 50%;
            top: -30px;
            border-radius: 4px;
            transform: translateX(-50%)
        }

        @media all and (max-width: 768px) {
            h2.separate:after {
                left: 30px
            }
        }

        .btn-primary {
            justify-content: center;
            background: #bad606;
            color: #000;
            border: 1px solid #bad606;
            transition-duration: .4s;
            z-index: 0;
            position: relative;
            width: -webkit-fit-content;
            width: -moz-fit-content;
            width: fit-content;
            padding: 10px 16px;
            margin: 24px 0;
            font-size: 16px;
            font-weight: 700;
            line-height: 24px;
            border-radius: 32px;
            text-decoration: none;
            overflow: hidden
        }

        .btn-primary img {
            vertical-align: middle
        }

        .btn-primary:hover {
            border: 1px solid #ddeb83;
            transition-duration: .4s
        }

        .btn-primary:active {
            transform: translateY(5px)
        }

        .btn-primary::after {
            content: "";
            position: absolute;
            top: 0;
            left: 0;
            height: 100%;
            width: 0;
            background: #fff;
            opacity: .5;
            transition: width .4s;
            z-index: -1
        }

        .btn-primary:hover::after {
            width: 100%
        }

        .btn-primary:focus,
        .btn-primary:active,
        .btn-primary:hover {
            background-color: var(--color-primary);
            border-color: var(--color-primary)
        }

        .btn-primary:hover,
        .btn-primary:visited {
            color: #000
        }

        .btn-secondary {
            background: #fff;
            color: #000;
            width: -webkit-fit-content;
            width: -moz-fit-content;
            width: fit-content;
            padding: 10px 16px;
            margin: 24px 0;
            border: 1px solid var(--color-primary);
            transition-duration: .4s;
            z-index: 0;
            position: relative;
            justify-content: center;
            font-size: 16px;
            font-weight: 700;
            line-height: 24px;
            border-radius: 32px;
            text-decoration: none;
            overflow: hidden
        }

        .btn-secondary img {
            filter: var(--invert);
            vertical-align: middle
        }

        @media(prefers-color-scheme: dark) {
            .btn-secondary {
                background-color: #000;
                color: #fff
            }
        }

        .btn-secondary:hover,
        .btn-secondary:visited {
            color: #000
        }

        @media(prefers-color-scheme: dark) {

            .btn-secondary:hover,
            .btn-secondary:visited {
                color: #fff
            }
        }

        .btn-secondary::after {
            content: "";
            position: absolute;
            top: 0;
            left: 0;
            height: 100%;
            width: 0;
            background: #fff;
            opacity: .5;
            transition: width .4s;
            z-index: -1
        }

        .btn-secondary:hover::after {
            width: 100%
        }

        .btn-secondary:focus {
            outline: none !important
        }

        @media(prefers-color-scheme: dark) {
            .btn-secondary span img {
                filter: grayscale(1) brightness(1.5) contrast(1)
            }
        }

        .btn-link {
            background: rgba(0, 0, 0, 0);
            color: #000;
            width: -webkit-fit-content;
            width: -moz-fit-content;
            width: fit-content;
            padding: 10px 16px;
            margin: 24px 0;
            position: relative;
            font-size: 16px;
            font-weight: 700;
            line-height: 24px;
            border-radius: 32px;
            text-decoration: underline;
            overflow: hidden
        }

        .btn-link:hover,
        .btn-link:visited {
            color: #000
        }

        .btn_anim {
            position: relative
        }

        .btn_anim::after {
            content: "";
            background:
                /*savepage-url=/fr/images/library/icons/chevron_black.svg*/
                url() no-repeat center center;
            background-size: cover;
            position: absolute;
            top: 50%;
            transform: translateY(-50%);
            -webkit-animation-name: slideright;
            animation-name: slideright;
            -webkit-animation-duration: 2.5s;
            animation-duration: 2.5s;
            left: calc(100% - 55px);
            -webkit-animation-iteration-count: infinite;
            animation-iteration-count: infinite;
            -webkit-animation-timing-function: linear;
            animation-timing-function: linear;
            width: 8px;
            height: 14px
        }

        .btn_anim span {
            padding-right: 65px !important
        }

        .btn-rounded {
            position: relative;
            display: block;
            width: -webkit-fit-content;
            width: -moz-fit-content;
            width: fit-content;
            padding: 10px 16px;
            margin: 24px 0;
            font-size: 16px;
            font-weight: 700;
            line-height: 24px;
            border-radius: 32px;
            text-decoration: none;
            overflow: hidden
        }

        .btn-green {
            background: #bad606;
            color: #000;
            border: 1px solid #bad606;
            transition-duration: .4s
        }

        .btn-green:hover {
            border: 1px solid #ddeb83;
            transition-duration: .4s
        }

        .btn-green:hover,
        .btn-green:visited {
            color: #000
        }

        .btn-transparent {
            background: rgba(0, 0, 0, 0);
            color: #000;
            border: 1px solid #bad606
        }

        .btn-transparent:hover,
        .btn-transparent:visited {
            color: #000
        }

        .btn-hover {
            z-index: 0
        }

        .btn-hover::after {
            content: "";
            position: absolute;
            top: 0;
            left: 0;
            height: 100%;
            width: 0;
            background: #fff;
            opacity: .5;
            transition: width .4s;
            z-index: -1
        }

        .btn-hover:hover::after {
            width: 100%
        }

        .btn_yellow>span {
            background-color: #bad606;
            color: #000
        }

        .btn_green>span {
            background-color: #bad606;
            color: #000;
            border: 1px solid #bad606;
            transition-duration: .4s
        }

        .btn_green>span:hover {
            border: 1px solid #ddeb83;
            transition-duration: .4s
        }

        .btn_black>span {
            background-color: #fff;
            color: #0a0a0a;
            border: 1px solid #bad606;
            line-height: 24px
        }

        .btn_black_banner>span {
            background-color: #fff;
            border: 1px solid #bad606
        }

        .btn_white>span {
            background-color: #f8f8f8;
            color: #000
        }

        .btn_grey>span {
            background-color: #c3c3c3;
            color: #000
        }

        .btn_hover>span {
            position: relative;
            padding: 10px 16px;
            font-size: 16px;
            display: inline-flex;
            justify-content: center;
            text-decoration: none;
            font-weight: bold;
            text-align: center;
            z-index: 0;
            border-radius: 32px;
            overflow: hidden
        }

        .btn_hover {
            text-decoration: none !important
        }

        .btn_hover:hover>span::after {
            width: 100%
        }

        .btn_hover>span::after {
            background-color: #fff;
            opacity: .5;
            content: "";
            display: block;
            width: 0;
            transition: width .4s;
            position: absolute;
            left: 0;
            top: 0;
            height: 100%;
            z-index: -1
        }

        @-webkit-keyframes slideright {
            0% {
                left: calc(100% - 55px)
            }

            10% {
                left: calc(100% - 45px)
            }

            20% {
                left: calc(100% - 55px)
            }

            40% {
                left: calc(100% - 15px)
            }

            60% {
                left: calc(100% - 55px)
            }

            100% {
                left: calc(100% - 55px)
            }
        }

        @keyframes slideright {
            0% {
                left: calc(100% - 55px)
            }

            10% {
                left: calc(100% - 45px)
            }

            20% {
                left: calc(100% - 55px)
            }

            40% {
                left: calc(100% - 15px)
            }

            60% {
                left: calc(100% - 55px)
            }

            100% {
                left: calc(100% - 55px)
            }
        }

        .capsule-ekoo {
            padding-right: 16px;
            border-radius: 32px;
            background: var(--bg-primary);
            box-shadow: rgba(0, 0, 0, .12) 0px 4px 8px;
