        }

        @-webkit-keyframes ekooPulse {
            0% {
                box-shadow: 0 0 0 0 rgba(130, 6, 214, .7019607843)
            }

            70% {
                box-shadow: 0 0 0 15px rgba(130, 6, 214, 0)
            }

