        .ei_tile {
            padding: 0;
            background-color: #fff;
            position: relative;
            cursor: default;
            transition: all .2s linear
        }

        .ei_tile .ei_tile_body,
        .ei_tile .ei_tile_footer {
            display: none
        }

        .ei_tile.ei_tile_expanded .ei_tile_body,
        .ei_tile.ei_tile_expanded .ei_tile_footer {
            display: block
        }

        .ei_tile.ei_border_dot {
            border: 3px #000;
            border-style: dotted !important
        }

        .ei_tile.ei_border_solid {
            border: 3px #000;
            border-style: solid !important
        }

        .ei_tile.ei_border_none {
            border-style: none !important
        }

        .ei_tile-status {
            display: flex;
            flex-direction: column
        }

        .ei_tile-status .ei_tile_status {
            order: 0
        }

        .ei_tile-status .ei_tile_header {
            order: 1
        }

        .ei_tile-status .ei_tile_body {
            order: 2
        }

        .ei_tile-status .ei_tile_footer {
            order: 3
        }

        .ei_tile-status.ei_tile .ei_tile_header {
            border-top-left-radius: 0;
            border-top-right-radius: 0
