        @-webkit-keyframes dotPulsation {
            0% {
                -webkit-transform: scale(.5);
                transform: scale(.5)
            }

            1.75% {
                -webkit-transform: scale(1);
                transform: scale(1)
            }

            3.5% {
                -webkit-transform: scale(.5);
